#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Query a foundation model using Model Serving
 *
 * This example demonstrates:
 * - Querying a foundation model endpoint (databricks-gpt-oss-120b)
 * - Sending chat messages with system and user prompts
 * - Processing model responses
 * - Using temperature and max_tokens parameters
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - Access to foundation model endpoints
 * - MODEL_NAME environment variable (optional, defaults to "databricks-gpt-oss-120b")
 *
 * Usage:
 *   npx ts-node examples/workspace/ml/query-model.ts
 *   MODEL_NAME="my-custom-model" npx ts-node examples/workspace/ml/query-model.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";
import {marked} from "marked";
import TerminalRenderer from "marked-terminal";

// TODO: This is a temporary interface to parse the response from the model.
interface GptReasoningContent {
    type: "reasoning";
    summary: {
        type: "summary_text";
        text: string;
    }[];
}

interface GptTextContent {
    type: "text";
    text: string;
}

type GptMessageContent = Array<GptReasoningContent | GptTextContent>;

marked.setOptions({
    renderer: new TerminalRenderer(),
});

async function main() {
    const client = new WorkspaceClient({});

    // Foundation model endpoint name (read from environment variable with fallback)
    const endpointName = process.env.MODEL_NAME || "databricks-gpt-oss-120b";

    console.log(`Querying foundation model: ${endpointName}`);

    // Query the model with system and user prompts
    const response = await client.servingEndpoints.query({
        name: endpointName,
        messages: [
            {
                role: "system",
                content:
                    "You are a helpful AI assistant that provides concise and accurate answers about data engineering and analytics.",
            },
            {
                role: "user",
                content:
                    "What is Apache Spark and why is it important for big data processing?",
            },
        ],
        max_tokens: 500,
        temperature: 0.7,
    });

    console.log(`✓ Model query successful\n`);

    // Display the response
    for (const choice of response.choices ?? []) {
        for (const content of (choice.message
            ?.content as unknown as GptMessageContent) ?? []) {
            if (content.type === "reasoning") {
                console.log(marked(`## Reasoning:`));
                console.log(
                    marked(content.summary.map((s) => s.text).join("\n\n"))
                );
            } else if (content.type === "text") {
                console.log(marked(`## Text:`));
                console.log(marked(content.text));
            }
        }
    }

    // Display token usage if available
    if (response.usage) {
        console.log(`Token Usage:`);
        console.log(`  Prompt tokens: ${response.usage.prompt_tokens || 0}`);
        console.log(
            `  Completion tokens: ${response.usage.completion_tokens || 0}`
        );
        console.log(`  Total tokens: ${response.usage.total_tokens || 0}`);
    }

    // Display model information
    if (response.model) {
        console.log(`\nModel: ${response.model}`);
    }
}

main();
